parameters.jsCode:
const request = $input.first().json;
const rawHeaders = (request.headers && typeof request.headers === 'object' && !Array.isArray(request.headers)) ? request.headers : {};
const headers = Object.fromEntries(
  Object.entries(rawHeaders).map(([key, value]) => [String(key).toLowerCase(), value])
);
const sanitizedHeaders = Object.fromEntries(
  Object.entries(rawHeaders).filter(([key]) => {
    const normalizedKey = String(key).toLowerCase();
    return normalizedKey !== 'x-api-key' && normalizedKey !== 'authorization';
  })
);
const sanitizedRequest = {
  ...request,
  headers: sanitizedHeaders
};
const headerValue = (value) => Array.isArray(value) ? String(value[0] || '').trim() : String(value || '').trim();
const expectedApiKey = String($env.N8N_WEBHOOK_API_KEY || '').trim();
const xApiKey = headerValue(headers['x-api-key']);
const authorization = headerValue(headers.authorization);
const bearerMatch = authorization.match(/^Bearer\s+(.+)$/i);
const bearerToken = bearerMatch ? String(bearerMatch[1] || '').trim() : '';
const matchedXApiKey = Boolean(expectedApiKey) && xApiKey === expectedApiKey;
const matchedBearer = Boolean(expectedApiKey) && bearerToken === expectedApiKey;
const authenticated = matchedXApiKey || matchedBearer;

if (authenticated) {
  return [{
    json: {
      ...sanitizedRequest,
      webhook_auth: {
        authenticated: true,
        header: matchedXApiKey ? 'X-API-Key' : 'Authorization'
      }
    },
    pairedItem: {
      item: 0
    }
  }];
}

const message = 'Unauthorized: Invalid or missing API key';

return [{
  json: {
    ...sanitizedRequest,
    status: 'error',
    message,
    code: 401,
    webhook_auth: {
      authenticated: false
    }
  },
  pairedItem: {
    item: 0
  }
}];

const rawBody = $input.first()?.json?.body;
const input = (rawBody && typeof rawBody === 'object' && !Array.isArray(rawBody)) ? rawBody : {};

const tenantId = String(input.tenant_id || '').trim();
const scope = String(input.scope || '').trim();
const task = input.task;

if (!tenantId || !scope || !task) {
  return [{
    json: {
      error: 'Missing required fields: tenant_id, scope, task'
    }
  }];
}

if (typeof task !== 'object' || task === null || Array.isArray(task)) {
  return [{
    json: {
      error: 'task must be an object'
    }
  }];
}

const requestId = String(input.request_id || '').trim() || `req-${Date.now()}-${Math.random().toString(36).slice(2,8)}`;

const output = {
  timestamp: new Date().toISOString(),
  task,
  status: 'received',
  executor: 'ai-executor'
};

return [{
  json: {
    tenant_id: tenantId,
    scope,
    task,
    output,
    outcome: 'ok',
    request_id: requestId
  }
}];

const data = $input.first().json;

if (data.error) {
  return [{
    json: {
      status: 'error',
      message: data.error
    }
  }];
}

return [{
  json: data
}];

const validated = $('Check Validation').first().json;

if (validated.status === 'error') {
  return [{ json: validated }];
}

const response = $input.first().json;
const candidatePolicy = (response && typeof response.result === 'object' && !Array.isArray(response.result))
  ? response.result
  : (response && typeof response === 'object' && !Array.isArray(response) ? response : null);

const fallbackPolicy = {
  policy_id: 'fallback',
  policy_version: 'fallback',
  decision: 'deny',
  allow: false,
  requires_approval: true,
  risk_score: 0,
  reasons: ['invalid_policy_response']
};

const policy = candidatePolicy || fallbackPolicy;
const decision = String(policy.decision || '').trim() || 'deny';

if (decision !== 'allow') {
  return [{
    json: {
      status: 'error',
      message: decision === 'requires_approval' ? 'Policy requires approval' : 'Policy denied',
      request_id: validated.request_id,
      policy: {
        ...policy,
        decision
      },
      approval: decision === 'requires_approval' ? {
        endpoint: '/webhook/policy/approval',
        method: 'POST'
      } : null
    }
  }];
}

return [{
  json: {
    ...validated,
    policy: {
      ...policy,
      decision
    }
  }
}];

const data = $input.first().json;

if (data.status === 'error') {
  return [{ json: data }];
}

const task = data.task || {};
const payload = task.payload || {};

if (task.type !== 'security_digest_mail') {
  return [{ json: data }];
}

const message = [
  '以下の事実データから、読みやすい日本語メルマガ本文を作成してください。',
  '',
  '要件:',
  '- 構成: 1) 今日の要点(3行) 2) 重要トピックTOP3 3) 業務影響の見方 4) 今日やることチェックリスト(5項目以内)',
  '- 誇張せず、根拠は事実データのみ',
  '- 1通で2-3分で読める分量',
  '- 平易で実務に使える日本語',
  '',
  '事実データ:',
  String(payload.message || ''),
].join('\n');

return [{
  json: {
    ...data,
    _brain_enabled: true,
    brain_input: {
      tenant_id: data.tenant_id || 'corp-internal',
      scope: data.scope || 'security-digest',
      message,
      meta: {
        source: '04_executor_dispatch',
        use_case: 'daily_digest_executor'
      },
      brain: {
        provider: task.llm?.provider || 'openrouter',
        model: task.llm?.model || 'qwen/qwen3-next-80b-a3b-instruct:free',
        temperature: 0.3
      }
    }
  }
}];

const brainResp = $input.first().json || {};
const context = $('Prepare Brain Payload').first().json._executor_context || {};

if (!context || Object.keys(context).length === 0) {
  return [{ json: brainResp }];
}

const task = context.task || {};
const payload = task.payload || {};

if (task.type !== 'security_digest_mail') {
  return [{ json: context }];
}

const llmText = (brainResp.ok === true && String(brainResp.status || '').toUpperCase() === 'OK')
  ? String(brainResp.answer || '').trim()
  : '';

const finalMessage = llmText
  ? `${llmText}\n\n---\n[Source Facts]\n${String(payload.message || '')}`
  : String(payload.message || '');

const safeSubject = String(payload.subject || 'Daily Security Digest').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const safeBody = finalMessage.replace(/</g, '&lt;').replace(/>/g, '&gt;');
const finalHtml = `<h2>${safeSubject}</h2><pre>${safeBody}</pre>`;

const updatedTask = {
  ...task,
  payload: {
    ...payload,
    message: finalMessage,
    htmlMessage: finalHtml
  }
};

return [{
  json: {
    ...context,
    task: updatedTask,
    output: {
      ...(context.output || {}),
      task: updatedTask,
      llm: {
        provider: brainResp.provider || 'openrouter',
        status: brainResp.status || 'ERROR'
      }
    },
    outcome: llmText ? 'ok' : 'ok_with_local_fallback'
  }
}];

const data = $input.first().json || {};

const output = (data.output && typeof data.output === 'object')
  ? data.output
  : {
      timestamp: new Date().toISOString(),
      task: data.task || {},
      status: 'received',
      executor: 'ai-executor'
    };

return [{
  json: {
    ...data,
    status: 'success',
    request_id: data.request_id || null,
    outcome: data.outcome || 'ok',
    output
  }
}];

